const int LSZ = sizeof(LEOPARD) / sizeof(*LEOPARD);

int go_brute(int l, int r) {
	int ans = 0;
	for (int i = 0; i < LSZ && LEOPARD[i] <= r; ++i) {
		for (int j = 0; j < LSZ && LEOPARD[i] + LEOPARD[j] <= r; ++j) {
			for (int k = 0; k < LSZ && LEOPARD[i] + LEOPARD[j] + LEOPARD[k] <= r; ++k) {
				long long x = (long long)LEOPARD[i] + LEOPARD[j] + LEOPARD[k];
				if (l <= x && x <= r) ++ans;
			}
		}
	}
	return ans;
}

int main() {
	int q; scanf("%d", &q);
	for (int j = 0; j < q; ++j) {
		int l, r; scanf("%d%d", &l, &r);
		printf("%d\n", go_brute(l, r));
	}
}